import e from"../index.min.js";import{hwid as t}from"./discover.min.js";export async function getOrCreateIdentity(){const n=t();if(!n)return null;const r=await e.hash(n,null,null,{name:"SHA-256",encode:"base62"});return{pair:await e.pair(null,{seed:r}),seed:r,hwid:n}}export async function getIdentity(){return getOrCreateIdentity()}